interface PaginationProps {
  currentPage: number;
  totalPages: number;
  onPageChange?: (page: number) => void;
  size?: "large" | "small";
}

function getPageRange(current: number, total: number, size: "large" | "small") {
  const neighbors = size === "large" ? 2 : 1;
  const atStart = current <= neighbors + 1;
  const atEnd = current >= total - neighbors;

  let start: number;
  let end: number;

  if (atStart) {
    start = 1;
    end = Math.min(total, size === "large" ? 5 : 3);
  } else if (atEnd) {
    start = Math.max(1, total - (size === "large" ? 4 : 2));
    end = total;
  } else {
    start = current - neighbors;
    end = current + neighbors;
  }

  const pages: number[] = [];
  for (let i = start; i <= end; i++) pages.push(i);
  return { pages, showFirst: start > 1, showLast: end < total };
}

export default function Pagination({
  currentPage,
  totalPages,
  onPageChange,
  size = "large",
}: PaginationProps) {
  const { pages, showFirst, showLast } = getPageRange(currentPage, totalPages, size);

  return (
    <nav className={`${styles.nav} ${size === "large" ? styles.navLarge : styles.navSmall}`}>
      {showFirst && (
        <>
          <button
            type="button"
            onClick={() => onPageChange?.(1)}
            className={styles.arrowButton}
            aria-label="First page"
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M10 3L5 8L10 13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
              <path d="M6 3L1 8L6 13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" transform="translate(8, 0)" />
            </svg>
          </button>
          <button
            type="button"
            onClick={() => onPageChange?.(currentPage - 1)}
            className={styles.arrowButton}
            aria-label="Previous page"
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M10 3L5 8L10 13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
        </>
      )}

      {pages.map((page) => (
        <button
          key={page}
          type="button"
          onClick={() => page !== currentPage && onPageChange?.(page)}
          className={page === currentPage ? styles.currentPage : styles.pageButton}
          style={page === currentPage ? { backgroundImage: STAMP_BG } : undefined}
          aria-current={page === currentPage ? "page" : undefined}
        >
          {page}
        </button>
      ))}

      {(showLast || (!showLast && currentPage < totalPages)) && (
        <>
          <button
            type="button"
            onClick={() => onPageChange?.(currentPage + 1)}
            className={styles.arrowButton}
            aria-label="Next page"
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M6 3L11 8L6 13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
          <button
            type="button"
            onClick={() => onPageChange?.(totalPages)}
            className={styles.arrowButton}
            aria-label="Last page"
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M6 3L11 8L6 13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
              <path d="M6 3L11 8L6 13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" transform="translate(-4, 0)" />
            </svg>
          </button>
        </>
      )}
    </nav>
  );
}
